163: // Discovery provides service discovery functionality based
164: // on files that contain target groups in JSON or YAML format. Refreshing
165: // happens using file watches and periodic refreshes.
166: type Discovery struct {
167: 	paths      []string
168: 	watcher    *fsnotify.Watcher
169: 	interval   time.Duration
170: 	timestamps map[string]float64
171: 	lock       sync.RWMutex
172: 
173: 	// lastRefresh stores which files were found during the last refresh
174: 	// and how many target groups they contained.
175: 	// This is used to detect deleted target groups.
176: 	lastRefresh map[string]int
177: 	logger      *slog.Logger
178: 
179: 	metrics *fileMetrics
180: }
181: 
182: // NewDiscovery returns a new file discovery for the given paths.
183: func NewDiscovery(conf *SDConfig, logger *slog.Logger, metrics discovery.DiscovererMetrics) (*Discovery, error) {
184: 	fm, ok := metrics.(*fileMetrics)
185: 	if !ok {
186: 		return nil, errors.New("invalid discovery metrics type")
187: 	}
188: 
189: 	if logger == nil {
190: 		logger = promslog.NewNopLogger()
191: 	}
192: 
193: 	disc := &Discovery{
194: 		paths:      conf.Files,
195: 		interval:   time.Duration(conf.RefreshInterval),
196: 		timestamps: make(map[string]float64),
197: 		logger:     logger,
198: 		metrics:    fm,
199: 	}
200: 
201: 	fm.init(disc)
202: 
203: 	return disc, nil
204: }
205: 
206: // listFiles returns a list of all files that match the configured patterns.
207: func (d *Discovery) listFiles() []string {
208: 	var paths []string
209: 	for _, p := range d.paths {
210: 		files, err := filepath.Glob(p)
211: 		if err != nil {
212: 			d.logger.Error("Error expanding glob", "glob", p, "err", err)
213: 			continue
214: 		}
215: 		paths = append(paths, files...)
216: 	}
217: 	return paths
218: }
219: 
220: // watchFiles sets watches on all full paths or directories that were configured for
221: // this file discovery.
222: func (d *Discovery) watchFiles() {
223: 	if d.watcher == nil {
224: 		panic("no watcher configured")
225: 	}
226: 	for _, p := range d.paths {
227: 		if dir, _ := filepath.Split(p); dir != "" {
228: 			p = dir
229: 		} else {
230: 			p = "./"
231: 		}
232: 		if err := d.watcher.Add(p); err != nil {
233: 			d.logger.Error("Error adding file watch", "path", p, "err", err)
234: 		}
235: 	}
236: }
