151: func (c *DynamicCertKeyPairContent) watchCertKeyFile(stopCh <-chan struct{}) error {
152: 	// Trigger a check here to ensure the content will be checked periodically even if the following watch fails.
153: 	c.queue.Add(workItemKey)
154: 
155: 	w, err := fsnotify.NewWatcher()
156: 	if err != nil {
157: 		return fmt.Errorf("error creating fsnotify watcher: %v", err)
158: 	}
159: 	defer w.Close()
160: 
161: 	if err := w.Add(c.certFile); err != nil {
162: 		return fmt.Errorf("error adding watch for file %s: %v", c.certFile, err)
163: 	}
164: 	if err := w.Add(c.keyFile); err != nil {
165: 		return fmt.Errorf("error adding watch for file %s: %v", c.keyFile, err)
166: 	}
167: 	// Trigger a check in case the file is updated before the watch starts.
168: 	c.queue.Add(workItemKey)
169: 
170: 	for {
171: 		select {
172: 		case e := <-w.Events:
173: 			if err := c.handleWatchEvent(e, w); err != nil {
174: 				return err
175: 			}
176: 		case err := <-w.Errors:
177: 			return fmt.Errorf("received fsnotify error: %v", err)
178: 		case <-stopCh:
179: 			return nil
180: 		}
181: 	}
182: }
