157: // syncCerts gets newTLSContent, if it has changed from the existing, the content is parsed and stored for usage in
158: // GetConfigForClient.
159: func (c *DynamicServingCertificateController) syncCerts() error {
160: 	newContent, err := c.newTLSContent()
161: 	if err != nil {
162: 		return err
163: 	}
164: 	// if the content is the same as what we currently have, we can simply skip it.  This works because we are single
165: 	// threaded.  If you ever make this multi-threaded, add a lock.
166: 	if newContent.Equal(c.currentlyServedContent) {
167: 		return nil
168: 	}
169: 
170: 	// make a shallow copy and override the dynamic pieces which have changed.
171: 	newTLSConfigCopy := c.baseTLSConfig.Clone()
172: 
173: 	// parse new content to add to TLSConfig
174: 	if len(newContent.clientCA.caBundle) > 0 {
175: 		newClientCAPool := x509.NewCertPool()
176: 		newClientCAs, err := cert.ParseCertsPEM(newContent.clientCA.caBundle)
177: 		if err != nil {
178: 			return fmt.Errorf("unable to load client CA file %q: %v", string(newContent.clientCA.caBundle), err)
179: 		}
180: 		for i, cert := range newClientCAs {
181: 			klog.V(2).InfoS("Loaded client CA", "index", i, "certName", c.clientCA.Name(), "certDetail", GetHumanCertDetail(cert))
182: 			if c.eventRecorder != nil {
183: 				c.eventRecorder.Eventf(&corev1.ObjectReference{Name: c.clientCA.Name()}, nil, corev1.EventTypeWarning, "TLSConfigChanged", "CACertificateReload", "loaded client CA [%d/%q]: %s", i, c.clientCA.Name(), GetHumanCertDetail(cert))
184: 			}
185: 
186: 			newClientCAPool.AddCert(cert)
187: 		}
188: 
189: 		newTLSConfigCopy.ClientCAs = newClientCAPool
190: 	}
191: 
192: 	if len(newContent.servingCert.cert) > 0 && len(newContent.servingCert.key) > 0 {
193: 		cert, err := tls.X509KeyPair(newContent.servingCert.cert, newContent.servingCert.key)
194: 		if err != nil {
195: 			return fmt.Errorf("invalid serving cert keypair: %v", err)
196: 		}
197: 
198: 		x509Cert, err := x509.ParseCertificate(cert.Certificate[0])
199: 		if err != nil {
200: 			return fmt.Errorf("invalid serving cert: %v", err)
201: 		}
202: 
203: 		klog.V(2).InfoS("Loaded serving cert", "certName", c.servingCert.Name(), "certDetail", GetHumanCertDetail(x509Cert))
204: 		if c.eventRecorder != nil {
205: 			c.eventRecorder.Eventf(&corev1.ObjectReference{Name: c.servingCert.Name()}, nil, corev1.EventTypeWarning, "TLSConfigChanged", "ServingCertificateReload", "loaded serving cert [%q]: %s", c.servingCert.Name(), GetHumanCertDetail(x509Cert))
206: 		}
207: 
208: 		newTLSConfigCopy.Certificates = []tls.Certificate{cert}
209: 	}
210: 
211: 	if len(newContent.sniCerts) > 0 {
212: 		newTLSConfigCopy.NameToCertificate, err = c.BuildNamedCertificates(newContent.sniCerts)
213: 		if err != nil {
214: 			return fmt.Errorf("unable to build named certificate map: %v", err)
215: 		}
216: 
217: 		// append all named certs. Otherwise, the go tls stack will think no SNI processing
218: 		// is necessary because there is only one cert anyway.
219: 		// Moreover, if servingCert is not set, the first SNI
220: 		// cert will become the default cert. That's what we expect anyway.
221: 		for _, sniCert := range newTLSConfigCopy.NameToCertificate {
222: 			newTLSConfigCopy.Certificates = append(newTLSConfigCopy.Certificates, *sniCert)
223: 		}
224: 	}
225: 
226: 	// store new values of content for serving.
227: 	c.currentServingTLSConfig.Store(newTLSConfigCopy)
228: 	c.currentlyServedContent = newContent // this is single threaded, so we have no locking issue
229: 
230: 	return nil
231: }
