238: // Run starts the kube-apiserver and blocks until stopCh is closed.
239: func (c *DynamicServingCertificateController) Run(workers int, stopCh <-chan struct{}) {
240: 	defer utilruntime.HandleCrash()
241: 	defer c.queue.ShutDown()
242: 
243: 	klog.InfoS("Starting DynamicServingCertificateController")
244: 	defer klog.InfoS("Shutting down DynamicServingCertificateController")
245: 
246: 	// synchronously load once.  We will trigger again, so ignoring any error is fine
247: 	_ = c.RunOnce()
248: 
249: 	// doesn't matter what workers say, only start one.
250: 	go wait.Until(c.runWorker, time.Second, stopCh)
251: 
252: 	// start timer that rechecks every minute, just in case.  this also serves to prime the controller quickly.
253: 	go wait.Until(func() {
254: 		c.Enqueue()
255: 	}, 1*time.Minute, stopCh)
256: 
257: 	<-stopCh
258: }
